use std::collections::HashMap;
use crate::error::ConfigError;
use crate::Value;

/// Parse a TOML value string into a Value enum variant.
fn parse_value(s: &str) -> Result<Value, ConfigError> {
    let s = s.trim();
    if s.starts_with('"') && s.ends_with('"') && s.len() >= 2 {
        return Ok(Value::String(s[1..s.len() - 1].to_string()));
    }
    if s == "true" {
        return Ok(Value::Boolean(true));
    }
    if s == "false" {
        return Ok(Value::Boolean(false));
    }
    if let Ok(i) = s.parse::<i64>() {
        return Ok(Value::Integer(i));
    }
    if let Ok(f) = s.parse::<f64>() {
        return Ok(Value::Float(f));
    }
    Err(ConfigError::ParseError(format!("invalid value: {}", s)))
}

/// Parse a TOML string into a nested HashMap of Values.
pub fn parse_toml(input: &str) -> Result<HashMap<String, Value>, ConfigError> {
    let mut root: HashMap<String, Value> = HashMap::new();
    let mut current_section: Option<String> = None;

    for (line_num, line) in input.lines().enumerate() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        if line.starts_with('[') && line.ends_with(']') {
            let name = line[1..line.len() - 1].trim().to_string();
            if name.is_empty() {
                return Err(ConfigError::ParseError(
                    format!("empty section name at line {}", line_num + 1),
                ));
            }
            root.entry(name.clone()).or_insert_with(|| Value::Table(HashMap::new()));
            current_section = Some(name);
            continue;
        }
        let Some((key, val_str)) = line.split_once('=') else {
            return Err(ConfigError::ParseError(
                format!("invalid line {}: {}", line_num + 1, line),
            ));
        };
        let key = key.trim().to_string();
        let value = parse_value(val_str)?;
        match &current_section {
            Some(section) => {
                if let Some(Value::Table(table)) = root.get_mut(section) {
                    table.insert(key, value);
                }
            }
            None => {
                root.insert(key, value);
            }
        }
    }
    Ok(root)
}

pub fn from_toml_str(input: &str) -> Result<Self, error::ConfigError> {
    let data = parser::parse_toml(input)?;
    Ok(Self { data })
}

pub fn from_toml_file(path: &str) -> Result<Self, error::ConfigError> {
    let content = std::fs::read_to_string(path)?;
    Self::from_toml_str(&content)
}

use configrs::{Config, Value};
use std::collections::HashMap;

#[test]
fn test_parse_simple_values() {
    let input = r#"
name = "myapp"
port = 8080
debug = true
rate = 1.5
"#;
    let config = Config::from_toml_str(input).unwrap();
    assert_eq!(config.get("name"), Some(&Value::String("myapp".into())));
    assert_eq!(config.get("port"), Some(&Value::Integer(8080)));
    assert_eq!(config.get("debug"), Some(&Value::Boolean(true)));
    assert_eq!(config.get("rate"), Some(&Value::Float(1.5)));
}

#[test]
fn test_parse_sections() {
    let input = r#"
[database]
host = "localhost"
port = 5432

[server]
port = 8080
"#;
    let config = Config::from_toml_str(input).unwrap();
    if let Some(Value::Table(db)) = config.get("database") {
        assert_eq!(db.get("host"), Some(&Value::String("localhost".into())));
        assert_eq!(db.get("port"), Some(&Value::Integer(5432)));
    } else {
        panic!("database section not found");
    }
}

#[test]
fn test_comments_ignored() {
    let input = "# This is a comment\nkey = 42\n";
    let config = Config::from_toml_str(input).unwrap();
    assert_eq!(config.get("key"), Some(&Value::Integer(42)));
}

#[test]
fn test_invalid_line_returns_error() {
    let input = "this is not valid toml";
    assert!(Config::from_toml_str(input).is_err());
}
